// src/pages/admin/AdminPortal.jsx
import { db } from '../../utils/firebase';
import { doc, getDoc, setDoc, deleteDoc, serverTimestamp } from 'firebase/firestore';

import React, { useState, useEffect } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import { KPI, Table } from '../../components/UI';
import { Badge, AdminComplaintModal } from '../../components/ComplaintCard';
import { timeAgo } from '../../utils/helpers';
import { collection, onSnapshot } from 'firebase/firestore';

export default function AdminPortal() {
  const { complaints, updateComplaint } = useApp();
  
  // Auth and Tab Switching States
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);
  const [loginId, setLoginId] = useState('');
  const [password, setPassword] = useState('');
  const [tab, setTab] = useState('overview'); // 'overview' or 'vendors'
  
  // Vendor Form & Data States
  const [vendors, setVendors] = useState([]);
  const [vId, setVId] = useState('');
  const [vPass, setVPass] = useState('');
  const [vName, setVName] = useState('');
  const [vStation, setVStation] = useState('Nagpur Junction');
  const [selectedModal, setSelectedModal] = useState(null);

  // Real-time Fetch Live Vendors Registry for Admin Monitoring UI
  useEffect(() => {
    if (!isAdminLoggedIn) return;
    const unsubscribe = onSnapshot(collection(db, "vendors"), (snap) => {
      const list = snap.docs.map(d => ({ id: d.id, ...d.data() }));
      setVendors(list);
    });
    return () => unsubscribe();
  }, [isAdminLoggedIn]);

  // Handle Authentication Validation
  const executeAdminAuthCheck = async (e) => {
    e.preventDefault();
    if (!loginId.trim() || !password) return alert("Please fill out credentials.");
    
    try {
      const adminDocRef = doc(db, "admins", loginId.trim());
      const snapshot = await getDoc(adminDocRef);
      
      if (snapshot.exists()) {
        if (snapshot.data().password === password) {
          setIsAdminLoggedIn(true);
        } else {
          alert("Invalid Password provided.");
        }
      } else {
        alert("Admin system profile not found in Firebase registry.");
      }
    } catch (err) {
      console.error("Auth Exception: ", err);
    }
  };

  // Vendor CRUD - Create Node Execution
  const handleAddVendorSubmit = async (e) => {
    e.preventDefault();
    if (!vId.trim() || !vPass || !vName.trim()) return alert("Fill all vendor fields.");

    try {
      await setDoc(doc(db, "vendors", vId.trim()), {
        loginId: vId.trim(),
        password: vPass,
        name: vName.trim(),
        stationName: vStation,
        createdAt: serverTimestamp()
      });
      setVId(''); setVPass(''); setVName('');
      alert("Vendor successfully registered!");
    } catch (err) {
      alert("Error saving vendor profile data registry.");
    }
  };

  // Vendor CRUD - Delete Action
  const handleWipeVendor = async (targetVendorId) => {
    if (!window.confirm("Confirm entire removal of vendor registry node?")) return;
    try {
      await deleteDoc(doc(db, "vendors", targetVendorId));
      alert("Vendor profile deleted from nodes.");
    } catch (err) {
      console.error("Error purging vendor row.", err);
    }
  };

  const currentSelected = complaints.find(c => c.id === selectedModal?.id) || selectedModal;

  // Table Generation logic for Complaints
  const headers = ['ID', 'Area/Location', 'Waste Category', 'Reported Time', 'Status Level'];
  const tableRows = complaints.map(c => ({
    onClick: () => setSelectedModal(c),
    cells: [
      c.customTicketId || c.id,
      c.area,
      `${c.emoji || '🗑️'} ${c.gtype}`,
      timeAgo(c.reportedAt),
      <Badge status={c.status} />
    ]
  }));

  // Render Login Gate Screen if not authorized yet
  if (!isAdminLoggedIn) {
    return (
      <div style={{ display: 'flex', height: '100vh', alignItems: 'center', justifyContent: 'center', background: '#0A1628', fontFamily: 'system-ui,sans-serif' }}>
        <form onSubmit={executeAdminAuthCheck} style={{ background: '#fff', padding: '32px 28px', borderRadius: 16, width: 340, boxShadow: '0 8px 30px rgba(0,0,0,0.3)' }}>
          <div style={{ fontSize: 20, fontWeight: 800, color: '#0A1628', marginBottom: 6, textAlign: 'center' }}>Express Travel HQ</div>
          <div style={{ fontSize: 13, color: '#546E7A', marginBottom: 24, textAlign: 'center', fontWeight: 500 }}>Admin Central Node Authentication</div>
          
          <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: '#3D4F61', marginBottom: 5 }}>ADMIN ACCESS ID</label>
          <input type="text" value={loginId} onChange={e => setLoginId(e.target.value)} placeholder="e.g. admin_ngp" style={{ width: '100%', padding: '10px 12px', borderRadius: 8, border: '1px solid #DDE3E9', marginBottom: 14, boxSizing: 'border-box', fontSize: 13 }} />
          
          <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: '#3D4F61', marginBottom: 5 }}>PASSWORD</label>
          <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="••••••••" style={{ width: '100%', padding: '10px 12px', borderRadius: 8, border: '1px solid #DDE3E9', marginBottom: 20, boxSizing: 'border-box', fontSize: 13 }} />
          
          <button type="submit" style={{ width: '100%', padding: 11, background: '#1565C0', color: '#fff', border: 'none', borderRadius: 8, fontWeight: 700, cursor: 'pointer', fontSize: 13 }}>Verify & Enter Control Hub</button>
        </form>
      </div>
    );
  }

  return (
    <div style={{ display: 'flex', height: '100vh', fontFamily: 'system-ui,sans-serif', overflow: 'hidden' }}>
      <Sidebar 
        title="Nagpur Junction" 
        subtitle="Admin Headquarter" 
        navItems={[
          { key: 'overview', icon: '🛡️', label: 'Dashboard Control' },
          { key: 'vendors', icon: '💼', label: 'Manage Vendors' }
        ]} 
        activeTab={tab} 
        onTabChange={setTab}
        footerUser={{ initials: 'AD', name: 'Station Master', role: 'Super Admin', avatarColor: '#B71C1C' }} 
      />
      
      <div style={{ flex: 1, overflowY: 'auto', background: '#F7F9FC', padding: 22 }}>
        {tab === 'overview' ? (
          <>
            <div style={{ fontSize: 18, fontWeight: 800, marginBottom: 14 }}>Nagpur Station Live Node Control Panel</div>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(140px,1fr))', gap: 12, marginBottom: 20 }}>
              <KPI label="Total Active Influx" value={complaints.length} />
              <KPI label="Critical Escalations" value={complaints.filter(c => c.severity === 'critical').length} color="#B71C1C" />
              <KPI label="Resolved Pipelines" value={complaints.filter(c => c.status === 'COMPLETED').length} color="#2E7D32" />
            </div>
            <div style={{ background: '#fff', border: '1px solid #DDE3E9', borderRadius: 14, padding: 12 }}>
              <Table headers={headers} rows={tableRows} />
            </div>
          </>
        ) : (
          <>
            <div style={{ fontSize: 18, fontWeight: 800, marginBottom: 14 }}>Vendor Core Registry Infrastructure</div>
            
            {/* Horizontal Sub Form Panel for Inline Vendor Creation */}
            <form onSubmit={handleAddVendorSubmit} style={{ display: 'flex', flexWrap: 'wrap', gap: 10, background: '#fff', padding: 14, borderRadius: 12, border: '1px solid #DDE3E9', marginBottom: 20, alignItems: 'flex-end' }}>
              <div style={{ flex: 1, minWidth: 140 }}>
                <span style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>VENDOR LOGIN ID</span>
                <input type="text" value={vId} onChange={e => setVId(e.target.value)} placeholder="vendor_01" style={{ width: '100%', padding: '7px 10px', fontSize: 12, borderRadius: 6, border: '1px solid #DDE3E9' }} />
              </div>
              <div style={{ flex: 1, minWidth: 140 }}>
                <span style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>PASSWORD</span>
                <input type="password" value={vPass} onChange={e => setVPass(e.target.value)} placeholder="vpass123" style={{ width: '100%', padding: '7px 10px', fontSize: 12, borderRadius: 6, border: '1px solid #DDE3E9' }} />
              </div>
              <div style={{ flex: 1, minWidth: 160 }}>
                <span style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>VENDOR MANAGEMENT NAME</span>
                <input type="text" value={vName} onChange={e => setVName(e.target.value)} placeholder="Rajesh Kumar" style={{ width: '100%', padding: '7px 10px', fontSize: 12, borderRadius: 6, border: '1px solid #DDE3E9' }} />
              </div>
              <div style={{ flex: 1, minWidth: 160 }}>
                <span style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>STATION NODES</span>
                <select value={vStation} onChange={e => setVStation(e.target.value)} style={{ width: '100%', padding: '7px 10px', fontSize: 12, borderRadius: 6, border: '1px solid #DDE3E9', background: '#fff' }}>
                  <option value="Nagpur Junction">Nagpur Junction (NGP)</option>
                  <option value="New Delhi Railway Station">New Delhi Railway Station (NDLS)</option>
                </select>
              </div>
              <button type="submit" style={{ padding: '8px 16px', background: '#2E7D32', color: '#fff', border: 'none', borderRadius: 6, fontWeight: 700, fontSize: 12, cursor: 'pointer' }}>+ Provision Vendor</button>
            </form>

            {/* Display Active Provisioned Vendors List */}
            <div style={{ background: '#fff', border: '1px solid #DDE3E9', borderRadius: 14, padding: 16 }}>
              <div style={{ fontWeight: 700, fontSize: 14, color: '#0A1628', marginBottom: 12 }}>Active System Operators ({vendors.length})</div>
              {vendors.length === 0 ? (
                <div style={{ color: '#7A8FA6', fontSize: 12, textAlign: 'center', padding: '20px 0' }}>No active operational vendors provisioned in network yet.</div>
              ) : (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', gap: 12 }}>
                  {vendors.map(v => (
                    <div key={v.id} style={{ border: '1px solid #DDE3E9', borderRadius: 10, padding: 12, background: '#F7F9FC', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <div>
                        <div style={{ fontSize: 13, fontWeight: 700, color: '#0A1628' }}>{v.name}</div>
                        <div style={{ fontSize: 11, color: '#546E7A', fontFamily: 'monospace', marginTop: 2 }}>ID: {v.loginId}</div>
                        <div style={{ fontSize: 11, color: '#1565C0', fontWeight: 600, marginTop: 4 }}>📍 {v.stationName}</div>
                      </div>
                      <button onClick={() => handleWipeVendor(v.id)} style={{ background: 'none', border: 'none', color: '#B71C1C', fontSize: 16, cursor: 'pointer', padding: '4px 8px' }} title="Revoke Vendor">🗑️</button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </>
        )}
      </div>
      
      {selectedModal && (
        <AdminComplaintModal 
          complaint={currentSelected} 
          onClose={() => setSelectedModal(null)} 
          onStatusChange={(id, nextStatus) => updateComplaint(id, { status: nextStatus })}
        />
      )}
    </div>
  );
}
